INSERT [dbo].[Project] ([Id], [UserId], [RequestDate], [Title], [Description], [InterviewCondition], [InterviewConditionComment], [InterviewResult], [InterviewResultComment], [MediaAssistantFinancialService], [ProducerFinancialService], [PromoterFinancialService], [WishContactedByMediaAssistant], [WishContactedByProducer], [WishContactedByPromoter], [Location], [RemoteLocation], [DueDate], [IsArchived], [IsPublished]) VALUES (N'69cd606a-19bc-41ac-8211-07611454de1f', N'f684831e-79d9-4af9-9661-7953de4bee7d', CAST(N'2022-04-03T16:37:50.6510000' AS DateTime2), N'Need a sports journalist or sports writer', N'We are looking for an author who understands the topic of sports for VYISKALI Magazine.
</br>
Ideally, if this is a journalist who knows the contacts of experts who can be knocked on for factual information or verification of information: trainers, nutritionists, sports. doctors.
</br>
But if you have written a lot about the topic of sports and understand some direction, it may also work. Ideal if you are familiar with the topic of running, swimming, FP or cycling.
</br>
</br>
Here''s how/what we write about:
- How to prepare for the Ironman competition: <a target="_blank" href="https://vskali.ru/articles/sport/kak-podgotovitsya-k-sorevnovaniyu-ironman/">https://vskali.ru/articles/sport/kak-podgotovitsya-k-sorevnovaniyu-ironman/</a>
- 10 tips on how to learn to swim crawl: <a target="_blank" href="https://vskali.ru/articles/sport/10-sovetov-kak-nauchitsya-plavat-krolem/">https://vskali.ru/articles/sport/10-sovetov-kak-nauchitsya-plavat-krolem/</a>
- 5 exercises that can be done at the desktop: <a target="_blank" href="https://vskali.ru/articles/sport/5-uprazhneniy-kotorye-mozhno-delat-u-rabochego-stola/">https://vskali.ru/articles/sport/5-uprazhneniy-kotorye-mozhno-delat-u-rabochego-stola/</a>
</br>
</br>
Not suitable for a beginner. We can’t work if you don’t understand the topic of sports: you will get stuck looking for experts, fact-checking and editing.
</br>
</br>
If you are familiar with the direction, there are interesting experts or heroes for an interview, fill out the form: <a target="_blank" href="https://docs.google.com/forms/d/15-Ynm79RLOqHStxqdozVdX8VJ3Nvym59xd9YkyZ920M/edit">https://docs.google.com/forms/d/15-Ynm79RLOqHStxqdozVdX8VJ3Nvym59xd9YkyZ920M/edit</a>', 0, N'', 0, N'', 0, 0, 0, 0, 1, 0, N'', 1, CAST(N'2022-07-16T05:00:00.0000000' AS DateTime2), 0, 1)
GO
INSERT [dbo].[Project] ([Id], [UserId], [RequestDate], [Title], [Description], [InterviewCondition], [InterviewConditionComment], [InterviewResult], [InterviewResultComment], [MediaAssistantFinancialService], [ProducerFinancialService], [PromoterFinancialService], [WishContactedByMediaAssistant], [WishContactedByProducer], [WishContactedByPromoter], [Location], [RemoteLocation], [DueDate], [IsArchived], [IsPublished]) VALUES (N'c909154b-18b3-4196-9319-0b22f221c369', N'f684831e-79d9-4af9-9661-7953de4bee7d', CAST(N'2022-04-03T16:34:34.3860000' AS DateTime2), N'Describe in detail the rules for working with the service and the requirements for drivers', N'To work in the service, you must pass a three-level check, including an interview. This process may seem too demanding to many, and we try to make it as seamless as possible. But the issue of child safety is not a dead sound for us, so we still make demands both in the process of selecting drivers and in the process of driving.
It is necessary to tell drivers about what can be done when transporting young passengers, what things are not allowed, so that this does not affect the outflow of drivers who fully comply with the requirements of the service, but are afraid of too complicated procedures.
</br>
</br>
Audience: mothers and women with a pedagogical education, 20-55 years old, owning a car, looking for urgent work and instant payments.
Men, 25-55 years old, may not be parents, but they are interested in working as a driver, with a higher check than in a taxi.
</br>
</br>
The limit on the number of characters with spaces is 3200 characters.
Budget from $5000.', 0, N'', 0, N'', 0, 0, 0, 0, 0, 1, N'', 1, CAST(N'2022-07-16T05:00:00.0000000' AS DateTime2), 0, 1)
GO
